const fs = require('fs');
const statePath = '/home/node/n8n-state/backfill-state.json';
const tmpPath = `${statePath}.tmp`;
const sessionCtx = $('Code: Parse Session Meta').item.json;
const sessionId = sessionCtx.session_id;
const outputDir = $('Code: Read Transcript').item.json.outputDir;
const ts = new Date().toISOString();

// Reload state (defensive: file may have been edited between load and now)
let state = { schema_version: '1', last_updated: null, completed: [], failed: [] };
if (fs.existsSync(statePath)) {
  try { state = JSON.parse(fs.readFileSync(statePath, 'utf8')); } catch (e) {}
}
state.completed = state.completed || [];
state.failed = state.failed || [];
state.last_updated = ts;

const body = $input.first().json;
const err = $input.first().error;

const logPath = `${outputDir}/ingest-error.log`;

function recordFailure(reason) {
  const report = `[${ts}] /ingest failed for ${sessionId}\nreason: ${reason}\nbody: ${JSON.stringify(body || {}, null, 2)}\n`;
  try { fs.writeFileSync(logPath, report, 'utf8'); } catch (e) {}
  state.failed = state.failed.filter(e => e.session_id !== sessionId);
  state.failed.push({ session_id: sessionId, failed_at: ts, reason: reason });
}

function recordPartial(b) {
  const warnings = b.warnings || [];
  const warningsText = warnings.length ? ('\n  - ' + warnings.join('\n  - ')) : ' (none)';
  const report = `[${ts}] /ingest partial failure for ${sessionId}\nchunks_written:  ${b.chunks_written}\nchunks_failed:   ${b.chunks_failed}\nchunks_skipped:  ${b.chunks_skipped_idempotent}\nchunks_by_type:  ${JSON.stringify(b.chunks_by_type || {})}\nwarnings:${warningsText}\n\nRe-run with force_reextract=true once upstream rate-limit/API issue resolves.\n`;
  try { fs.writeFileSync(logPath, report, 'utf8'); } catch (e) {}
  state.failed = state.failed.filter(e => e.session_id !== sessionId);
  state.failed.push({ session_id: sessionId, failed_at: ts, reason: `partial: ${b.chunks_failed} failed of ${b.chunks_written + b.chunks_failed}` });
}

function recordSuccess(b) {
  // Clear stale error log from prior failed/partial run
  try { if (fs.existsSync(logPath)) fs.unlinkSync(logPath); } catch (e) {}
  state.failed = state.failed.filter(e => e.session_id !== sessionId);
  // Dedup: remove any prior completed entry for this session_id
  state.completed = state.completed.filter(e => e.session_id !== sessionId);
  state.completed.push({
    session_id: sessionId,
    completed_at: ts,
    chunks_written: b.chunks_written
  });
}

if (err) {
  recordFailure(err.message || 'http error');
} else if (!body || typeof body.chunks_written !== 'number') {
  recordFailure('unexpected response shape');
} else if ((body.chunks_failed || 0) > 0) {
  recordPartial(body);
} else {
  recordSuccess(body);
}

fs.writeFileSync(tmpPath, JSON.stringify(state, null, 2), 'utf8');
fs.renameSync(tmpPath, statePath);

return { json: { session_id: sessionId, ingest_status: err ? 'failed' : ((body && body.chunks_failed > 0) ? 'partial' : 'ok') } };

const fs = require('fs');
const path = '/home/node/n8n-state/backfill-state.json';

let state = { schema_version: '1', last_updated: null, completed: [], failed: [] };
let existed = false;
if (fs.existsSync(path)) {
  existed = true;
  try {
    state = JSON.parse(fs.readFileSync(path, 'utf8'));
  } catch (e) {
    return { json: {
      summary: `Backfill run complete. State file at ${path} was unparseable: ${e.message}`,
      totalCompleted: 0, totalFailed: 0, error: e.message
    } };
  }
}

const totalCompleted = (state.completed || []).length;
const totalFailed = (state.failed || []).length;
const recentFailures = (state.failed || [])
  .slice(-5)
  .map(f => `  - ${f.session_id}: ${f.reason}`)
  .join('\n') || '  (none)';

const fileNote = existed ? '' : '\n(NOTE: state file did not exist -- workflow may not have processed any sessions)';

const summary = `Backfill run complete.${fileNote}

Completed (cumulative): ${totalCompleted}
Failed (cumulative):    ${totalFailed}
Last-updated:           ${state.last_updated}

Recent failures:
${recentFailures}
`;
console.log(summary);
return { json: { summary, totalCompleted, totalFailed, stateFileExisted: existed } };
